const trigger = $('Execute Sub-workflow Trigger').first().json;
const rows = $input.all().map(i => i.json);
const needed = new Set(trigger.step.depends_on || []);

const upstream_context = {};

for (const row of rows) {
  if (!needed.has(row.step_id)) continue;

  let parsed = {};
  try {
    parsed = JSON.parse(row.output_json || '{}');
  } catch (e) {
    parsed = {
      status: 'blocked',
      parse_error: true,
      raw: row.output_json || ''
    };
  }

  upstream_context[row.step_id] = parsed;
}

return [{
  json: {
    ...trigger,
    upstream_context
  }
}];

const step = $json.step;

const systemPrompt = `
You are a deterministic workflow step executor inside n8n.

You execute exactly one compiled prompt step.

Hard rules:
1. Execute ONLY the current step.
2. Do NOT perform downstream work.
3. Use the source prompt and upstream_context only as provided.
4. Preserve source-prompt constraints that still apply to this step.
5. If required information is missing, do not invent it.
6. If required information is missing or a quality gate cannot be passed:
   - set status = "blocked" or
   - set quality_gate_pass = false
   - explain the reason in open_gaps or warnings
7. Return every required output label exactly once in sections.
8. markdown_output must render the same sections in the same order using markdown headings.
9. For aggregate or recombine steps:
   - deduplicate overlap
   - compare conflicts
   - flag missing sections instead of filling them in
10. No filler. No preamble. No motivational language.
11. Self-check against the quality_gate before returning.

Output rules:
- Return only JSON matching the required schema.
- The section labels must match required_output_labels exactly.
`.trim();

const userPrompt = `
RUN CONTEXT
run_id: ${$json.runId}
graph_id: ${$json.graphId}
graph_name: ${$json.graphName}

SOURCE PROMPT
${$json.sourcePrompt}

CURRENT STEP MANIFEST
${JSON.stringify(step, null, 2)}

UPSTREAM CONTEXT
${JSON.stringify($json.upstream_context || {}, null, 2)}

Return only JSON matching the required schema.
`.trim();

return [{
  json: {
    ...$json,
    systemPrompt,
    userPrompt
  }
}];

const raw = $json;
let normalized = raw;

if (raw.output && typeof raw.output === 'object' && !Array.isArray(raw.output)) {
  normalized = raw.output;
} else if (raw.response && typeof raw.response === 'object' && !Array.isArray(raw.response)) {
  normalized = raw.response;
} else if (raw.text && typeof raw.text === 'string') {
  try {
    normalized = JSON.parse(raw.text);
  } catch (e) {
    throw new Error(`Step returned unparseable output: ${raw.text.slice(0, 1000)}`);
  }
}

return [{ json: normalized }];

const trigger = $('Execute Sub-workflow Trigger').first().json;
const step = trigger.step;
const result = { ...$json };

const labels = new Set((result.sections || []).map(s => s.label));
const required = step.required_output_labels || [];
const missing = required.filter(label => !labels.has(label));

const quality_gate_pass = Boolean(result.quality_gate_pass) && missing.length === 0;
const now = new Date().toISOString();

return [{
  json: {
    ...result,
    runId: trigger.runId,
    graphId: trigger.graphId,
    graphName: trigger.graphName,
    step_id: result.step_id || step.id,
    step_name: result.step_name || step.name,
    quality_gate_pass,
    warnings: [
      ...(result.warnings || []),
      ...(missing.length ? [`Missing required labels: ${missing.join(', ')}`] : [])
    ],
    result_key: `${trigger.runId}::${result.step_id || step.id}`,
    completed_at: now
  }
}];
